    {
      "keystrokes": "python3 tune_controller.py estimated_params.json --output tuned_gains.json\n",
      "duration": 1.0
    },
    {
      "keystrokes": "python3 hvac_simulator.py --control --setpoint 22.0 --duration 150 --output control_log.json\n",
      "duration": 1.0
